# 1. Combien y a-t-il de handle dans cette array ?
# count=compter les handles, handles=les handles
# handles.length=compter le nombre de handles(domaines) dans l'array
def count_handles(handles)

  handles.length
end

# 2. Quel est le handle le plus court de cette liste ?
# shortest=le plus court, handle=le handle, handles=les handles
# handles.min_by=trouver le handle le plus court, handle.length=calculer la longueur de chaque handle
def shortest_handle(handles)
  handles.min_by { |handle| handle.length }
end

# 3. Combien y-a-t'il de handle contenant 5 caractères (le @ ne compte pas pour un caractère)
# count=compter les handles, handles=les handles, handle.length=calculer la longueur de chaque handle
# handle.length == 6=compter les handles qui ont une longueur de 6 caractères (5 caractères + le '@')
def count_5_char_handles(handles)
  handles.count { |handle| handle.length == 6 } # 1 caractère pour '@' + 5 caractères
end

# 4. Combien commencent par une majuscule (première lettre juste après le @) ?
# count=compter les handles, uppercase=majuscule, handle=le handle, handles=les handles  
# count=compter les handles, handles=les handles, handle[1]=la première lettre après le '@', =~ /[A-Z]/=vérifier si la première lettre est une majuscule
def count_uppercase_handles(handles)
  handles.count { |handle| handle[1] =~ /[A-Z]/ }
end

# 5. Trie la liste de handle par ordre alphabétique.
# sort_by=trier les handles, alpha=alphabétique
# handles.sort_by=trier les handles, handle.downcase=convertir chaque handle en minuscules pour un tri insensible à la casse
def sort_handles_alpha(handles)
  handles.sort_by { |handle| handle.downcase }
end

# 6. Trie la liste de handle par taille des handle (les plus petits en premiers, les plus grands après)
# sort_handles_by_length=trier les handles par longueur, handles.sort_by=trier les handles, handle.length=calculer la longueur de chaque handle pour le tri
# handles.sort_by=trier les handles, handle.length=calculer la longueur de chaque handle pour le tri
def sort_handles_by_length(handles)
  handles.sort_by { |handle| handle.length }
end

# 7. Quelle est la position dans l'array de la personne @epenser?
# find_epenser_position=trouver la position de @epenser, handles.index=trouver l'index de @epenser dans l'array des handles
# handles.index("@epenser")=trouver l'index de @epenser dans l'array des handles, si @epenser n'est pas trouvé, index retourne nil
def find_epenser_position(handles)
  handles.index("@epenser")
end


# 8. Sors-moi une répartition des handle par taille de ces derniers
# handle_length_distribution=répartition des handles par taille, distribution=la répartition, Hash.new(0)=initialiser un hash avec une valeur par défaut de 0 pour les tailles de handle
# handles.each=parcourir chaque handle dans l'array des handles, length=calculer la longueur de chaque handle, distribution[length] += 1=incrémenter le compteur pour cette longueur de handle dans la répartition
# distribution=la répartition, length=la longueur de chaque handle, distribution[length] += 1=incrémenter le compteur pour cette longueur de handle dans la répartition
def handle_length_distribution(handles)
  distribution = Hash.new(0)
  handles.each do |handle|
    length = handle.length
    distribution[length] += 1
  end
  distribution
end

