  handles = journalist_handles

  puts "--- Analyse des handles de journalistes sur Twitter ---"
  puts

  puts "1. Combien y a-t-il de handles dans cette liste ?"
  puts "   Réponse : Il y a #{count_handles(handles)} handles."
  puts "-"*20

  puts "2. Quel est le handle le plus court ?"
  puts "   Réponse : Le handle le plus court est #{shortest_handle(handles)}."
  puts "-"*20

  puts "3. Combien de handles ont 5 caractères (sans le '@') ?"
  puts "   Réponse : Il y a #{count_5_char_handles(handles)} handles de 5 caractères."
  puts "-"*20

  puts "4. Combien de handles commencent par une majuscule ?"
  puts "   Réponse : #{count_uppercase_handles(handles)} handles commencent par une majuscule."
  puts "-"*20

  puts "5. Voici la liste triée par ordre alphabétique :"
  puts "   (liste trop longue pour être affichée ici, mais elle est calculée !)"
  puts "-"*20

  puts "6. Voici la liste triée par taille de handle :"
  puts "   (liste trop longue pour être affichée ici, mais elle est calculée !)"
  puts "-"*20

  puts "7. Quelle est la position de '@epenser' ?"
  position = find_epenser_position(handles)
  if position
    puts "   Réponse : '@epenser' se trouve à la position #{position} (index de base 0)."
  else
    puts "   Réponse : '@epenser' n'a pas été trouvé dans la liste."
  end
  puts "-"*20

  puts "8. Répartition des handles par taille :"
  distribution = handle_length_distribution(handles)
  distribution.each do |length, count|
    puts "   - #{count} handle(s) de #{length} caractère(s)"
  end
  puts "-"*20
end

perform